import { inject } from '@angular/core';
import { CanActivateFn, Router } from '@angular/router';
import { getAllRouteParams, isDefined } from '../../../shared/utils';

export const clientsGuard: CanActivateFn = (route, _state) => {
  const router = inject(Router);

  // Get all parameters including those from parent routes
  const allParams = getAllRouteParams(route);
  const vendorId = allParams['vendorId'];

  if (isDefined(vendorId)) {
    return router.createUrlTree([
      'admin',
      'vendor',
      vendorId,
      'clients',
      'grid',
      'vendor-clients',
    ]);
  }

  // If no vendorId, don't allow access to the route
  return false;
};
