import { Component, input, output, signal, effect } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { MultiSelectModule, MultiSelectChangeEvent } from 'primeng/multiselect';
import { ButtonModule } from 'primeng/button';
import { TooltipModule } from 'primeng/tooltip';
import { GridColumn } from '../../../models';
import { PopoverModule } from 'primeng/popover';

export interface ColumnOption {
  label: string;
  value: string;
  required?: boolean;
}

@Component({
  selector: 'app-column-selector',
  imports: [
    CommonModule,
    FormsModule,
    MultiSelectModule,
    ButtonModule,
    TooltipModule,
    PopoverModule,
  ],
  templateUrl: './column-selector.component.html',
  styleUrl: './column-selector.component.scss',
})
export class ColumnSelectorComponent<T = unknown> {
  readonly columns = input.required<GridColumn<T>[]>();
  readonly selectedColumns = input<string[]>([]);
  readonly disabled = input<boolean>(false);

  readonly columnChange = output<string[]>();

  readonly columnOptions = signal<ColumnOption[]>([]);
  readonly selectedValues = signal<string[]>([]);

  constructor() {
    // Update column options when columns change
    effect(() => {
      const cols = this.columns();
      const options = cols.map((col) => ({
        label: col.header,
        value: col.field,
      }));
      this.columnOptions.set(options);
    });

    // Update selected values when selectedColumns input changes
    effect(() => {
      const selected = this.selectedColumns();
      if (selected.length > 0) {
        this.selectedValues.set(selected);
      } else {
        // Default to all columns if none selected
        const allColumns = this.columns().map((col) => col.field);
        this.selectedValues.set(allColumns);
      }
    });
  }

  onSelectionChange(event: MultiSelectChangeEvent): void {
    const values = event.value as string[];
    this.selectedValues.set(values);
    this.columnChange.emit(values);
  }

  selectAll(): void {
    const allValues = this.columnOptions().map((option) => option.value);
    this.selectedValues.set(allValues);
    this.columnChange.emit(allValues);
  }

  clearAll(): void {
    // Keep only required columns
    const requiredValues = this.columnOptions()
      .filter((option) => option.required === true)
      .map((option) => option.value);
    this.selectedValues.set(requiredValues);
    this.columnChange.emit(requiredValues);
  }

  resetToDefault(): void {
    // Reset to all columns (different from selectAll behavior)
    this.selectAll();
  }
}
