import {
  ChangeDetectionStrategy,
  Component,
  DestroyRef,
  effect,
  inject,
  OnInit,
  signal,
  ViewChild,
} from '@angular/core';
import { ActivatedRoute, NavigationEnd, Router } from '@angular/router';
import {
  catchError,
  debounceTime,
  defer,
  EMPTY,
  filter,
  finalize,
  map,
  merge,
  Observable,
  Subject,
  switchMap,
  tap,
} from 'rxjs';

import { ButtonModule } from 'primeng/button';
import { TooltipModule } from 'primeng/tooltip';

import { GridComponent } from '../../../../shared/components/grid/grid.component';
import { ColumnSelectorComponent } from '../../../../shared/components/grid/column-selector/column-selector.component';
import { GridConfigurationFactory } from '../../../../shared/components/grid/grid-config-factory';
import {
  FilterChangeEvent,
  FilterValue,
  GridColumn,
  GridConfiguration,
  GridResponse,
  GridRowData,
} from '../../../../shared/models';
import { TableLazyLoadEvent, TableRowSelectEvent } from 'primeng/table';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { GridDataType, GridState } from '../../models/admin-grid.interface';
import { DEFAULT_PAGE_SIZE } from '../../../../core/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../shared/utils';
import { BroadcastEventMessageService } from '../../services/broadcast-event-messages.service';
import { DetailsComponentFactory } from '../../factories';
import { EntityDetailsService } from '../../services/entity/entity-details.service';
import { GridPreferenceService } from '../../../../shared/services/grid-preference.service';

/**
 * Container component that handles the dynamic creation and management of grid configurations.
 * Supports lazy loading and dynamic column configuration based on route parameters.
 */
@Component({
  selector: 'app-admin-grid-container',
  imports: [
    GridComponent,
    ColumnSelectorComponent,
    ButtonModule,
    TooltipModule,
  ],
  templateUrl: './admin-grid-container.component.html',
  styleUrl: './admin-grid-container.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class AdminGridContainerComponent implements OnInit {
  @ViewChild(GridComponent) readonly grid?: GridComponent;
  private readonly gridConfigurationFactory = inject(GridConfigurationFactory);
  private readonly activatedRoute = inject(ActivatedRoute);
  private readonly destroyRef = inject(DestroyRef);
  private readonly currentGridState = signal<GridState>(undefined);
  private readonly filterSubject = new Subject<FilterChangeEvent>();
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly detailsFactory = inject(DetailsComponentFactory);
  readonly detailsService = inject(EntityDetailsService);
  private readonly gridPreferenceService = inject(GridPreferenceService);

  protected gridConfiguration = signal<GridConfiguration<GridDataType> | null>(
    null,
  );
  protected columns = signal<GridColumn<GridDataType>[]>([]);
  protected data = signal<GridDataType[]>([]);
  protected loading = signal(false);
  protected totalRecords = signal<number>(0);
  protected limit = signal<number>(DEFAULT_PAGE_SIZE);
  readonly showFilters = signal<boolean>(false);
  protected currentFilters = signal<Record<string, FilterValue>>({});
  protected visibleColumns = signal<string[]>([]);
  private readonly router = inject(Router);
  private readonly forceGridReconfig$ = new Subject<void>();
  private readonly lastProcessedRouteKey = signal<string | null>(null);

  constructor() {
    effect(() => {
      const config = this.gridConfiguration();
      if (isDefined(config?.columnsSignal)) {
        this.columns.set(config.columnsSignal());
      }
    });
  }
  ngOnInit(): void {
    this.initializeGridConfiguration();
    this.initializeFilterDebounce();
    this.initializeEntityUpdatesHandler();
    this.initializeClientChangeHandler();
    this.forceGridReconfig$.next();
  }

  private selectGridItemFromQuery() {
    this.activatedRoute.queryParams
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        tap((params) => {
          // If data is already loaded, try to select the item
          if (this.data().length > 0 && isDefined(params['details'])) {
            const selectedId = params['details'];
            const selectedItem = this.data().find(
              (item) => item.id === selectedId,
            );
            if (selectedItem && this.grid) {
              // Use setTimeout to ensure the view is ready
              setTimeout(() => {
                this.grid?.setSelection(selectedItem);
                this.handleRowSelect({ data: selectedItem });
              });
            }
          }
        }),
      )
      .subscribe();
  }

  private initializeEntityUpdatesHandler(): void {
    this.broadcastService
      .on('entity-updated')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(() => {
        // First, save the ID of the currently selected item
        let currentSelection = null;

        if (this.grid?.selectedRows) {
          // Store the necessary data to restore selection
          currentSelection = Array.isArray(this.grid.selectedRows)
            ? [...this.grid.selectedRows]
            : { ...this.grid.selectedRows };
        }

        // Refresh the grid data using the current state
        this.loadData(this.currentGridState())
          .pipe(takeUntilDestroyed(this.destroyRef))
          .subscribe(() => {
            // After data is loaded, restore selection
            if (currentSelection) {
              this.restoreSelection(
                Array.isArray(currentSelection)
                  ? currentSelection[0]
                  : currentSelection,
              );
            }
          });
      });
  }

  private initializeClientChangeHandler(): void {
    const configChanges$ = merge(
      this.broadcastService.on('client-changed'),
      this.broadcastService.on('entity-changed'),
    );

    const dataChanges$ = this.broadcastService.on('entity-deleted');

    // Full grid reconfiguration for client and entity changes
    configChanges$
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        debounceTime(100), // Prevent multiple rapid refreshes
      )
      .subscribe(() => {
        this.forceGridReconfig$.next();
      });

    // Data refresh only for entity deletions
    dataChanges$
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        debounceTime(100), // Prevent multiple rapid refreshes
      )
      .subscribe(() => {
        // Just refresh the data, don't reconfigure the entire grid
        this.onRefresh();
      });
  }

  /**
   * Tries to restore a previously selected item
   */
  private restoreSelection(previousSelection: GridRowData): void {
    if (isNullOrUndefined(previousSelection) || !this.grid) return;

    if (this.data().length === 0) {
      console.warn('Cannot restore selection: grid data is empty');
      return;
    }

    try {
      if (Array.isArray(previousSelection)) {
        const selectedIds = previousSelection.map((item) => item.id);
        const refreshedItems = this.data().filter((item) =>
          selectedIds.includes(item.id),
        );

        if (refreshedItems.length > 0) {
          setTimeout(() => {
            this.grid?.setSelection(refreshedItems);
            if (isDefined(refreshedItems[0])) {
              this.handleRowSelect({ data: refreshedItems[0] });
            }
          }, 0); // Using 0ms for consistency
        }
      } else if (isDefined(previousSelection?.['id'])) {
        const refreshedItem = this.data().find(
          (item) => item.id === previousSelection['id'],
        );

        if (refreshedItem) {
          setTimeout(() => {
            this.grid?.setSelection(refreshedItem);
            this.handleRowSelect({ data: refreshedItem });
          }, 0); // Using 0ms for consistency
        } else {
          console.warn(
            `Item with id ${previousSelection['id']} not found in refreshed data`,
          );
        }
      }
    } catch (err) {
      console.error('Error restoring selection:', err);
    }
  }

  private initializeGridConfiguration() {
    const navigationEvents$ = this.router.events.pipe(
      filter((event): event is NavigationEnd => event instanceof NavigationEnd),
      map(() => false as boolean),
    );
    const forceReconfigEvents$ = this.forceGridReconfig$.pipe(
      map(() => true as boolean),
    );

    merge(navigationEvents$, forceReconfigEvents$)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        switchMap(() => {
          this.loading.set(true);

          const type = this.activatedRoute.snapshot.paramMap.get('type');
          const routeParams = this.getRouteParams();

          const ownerId =
            routeParams['clientId'] ??
            routeParams['vendorId'] ??
            routeParams['distributorId'] ??
            'none';
          const currentRouteKey = `${type}-${ownerId}`;

          if (this.lastProcessedRouteKey() === currentRouteKey) {
            this.loading.set(false);
            return EMPTY;
          }

          this.lastProcessedRouteKey.set(currentRouteKey);

          if (isNullOrUndefined(type)) {
            this.gridConfiguration.set(null);
            this.columns.set([]);
            this.currentFilters.set({});
            this.loading.set(false);
            return EMPTY;
          }

          const config = this.gridConfigurationFactory.create<GridDataType>(
            type,
            routeParams,
          );

          if (!this.isValidConfig(config)) {
            console.warn(
              `AdminGridContainer: Generated configuration for type "${type}" (key: ${currentRouteKey}) is invalid.`,
            );
            this.gridConfiguration.set(null);
            this.columns.set([]);
            this.currentFilters.set({});
            this.loading.set(false);
            return EMPTY;
          }

          this.gridConfiguration.set(config);
          this.columns.set(config.columns);

          // Load visible columns from preferences, falling back to defaults
          const savedVisibleColumns =
            this.gridPreferenceService.getVisibleColumns(config);
          this.visibleColumns.set(savedVisibleColumns);

          if (isDefined(config.getFilters)) {
            const filterState = config.getFilters();
            const initialFilters: Record<string, FilterValue> = {};
            Object.entries(filterState).forEach(([field, criteria]) => {
              if (isDefined(criteria) && typeof criteria === 'object') {
                initialFilters[field] = criteria.value;
              }
            });
            this.currentFilters.set(initialFilters);
          } else {
            this.currentFilters.set({});
          }
          return this.loadData();
        }),
        catchError((err) => {
          console.error(
            'AdminGridContainer: Error during grid configuration or data load pipeline:',
            err,
          );
          this.loading.set(false);
          this.data.set([]);
          this.totalRecords.set(0);
          this.gridConfiguration.set(null);
          this.columns.set([]);
          this.currentFilters.set({});
          return EMPTY;
        }),
      )
      .subscribe();
  }

  private getRouteParams(): Record<string, string | number> {
    let route: ActivatedRoute | null = this.activatedRoute;
    const paramsList: Record<string, string | number>[] = [];

    while (route) {
      paramsList.push(route.snapshot.params as Record<string, string | number>);
      route = route.parent;
    }

    const finalParams: Record<string, string | number> = {};
    for (let i = paramsList.length - 1; i >= 0; i--) {
      Object.assign(finalParams, paramsList[i]);
    }
    return finalParams;
  }

  private isValidConfig(
    config: GridConfiguration<GridDataType> | null,
  ): config is GridConfiguration<GridDataType> {
    // Check for essential parts of the configuration, e.g., dataService.
    return isDefined(config?.dataService);
  }

  private initializeFilterDebounce(): void {
    this.filterSubject
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        debounceTime(300), // Debounce filter changes by 300ms
        tap((event) => {
          const config = this.gridConfiguration();
          if (!config) return;

          config.onFilterChange?.(event.field, event.value);
          this.loadData(this.currentGridState()).subscribe(() => {});
        }),
      )
      .subscribe();
  }

  protected loadData(
    event?: TableLazyLoadEvent,
  ): Observable<GridResponse<GridDataType>> {
    return defer(() => {
      const config = this.gridConfiguration();

      if (!this.isValidConfig(config)) {
        // Guard against direct calls with invalid config
        this.loading.set(false); // Ensure loading is off if we bail early
        return EMPTY;
      }

      this.loading.set(true); // Explicitly set loading at the start of data fetching.

      this.currentGridState.set(event); // Store the actual event being used.

      return config.dataService.getList(config.getRequestParams(event)).pipe(
        takeUntilDestroyed(this.destroyRef),
        tap((response) => {
          this.data.set(response.items);
          this.totalRecords.set(response.count);
          this.selectGridItemFromQuery(); // Attempt to select item after data is loaded.
        }),
        catchError((err) => {
          console.error(
            `AdminGridContainer: Error loading data for type:`,
            err,
          );
          this.data.set([]); // Clear data on error.
          this.totalRecords.set(0); // Clear count on error.
          // loading.set(false) will be handled by finalize.
          return EMPTY;
        }),
        finalize(() => {
          this.loading.set(false); // Ensure loading is turned off when the stream completes or errors.
        }),
      );
    });
  }

  protected onExport(): void {
    this.grid?.exportCSV();
  }

  protected onRefresh(): void {
    const config = this.gridConfiguration();
    if (!this.isValidConfig(config)) {
      return;
    }

    // Store details panel state before refresh
    const hasSelectedItem = this.detailsService.showPanel();
    const selectedItemId = this.detailsService.getSelectedItemId();

    this.loadData(this.currentGridState())
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        tap(() => {
          // If we had an item selected, try to refresh its details too
          if (hasSelectedItem && selectedItemId) {
            const refreshedItem = this.findItemById(selectedItemId);
            if (isDefined(refreshedItem)) {
              this.detailsService.softRefreshSelectedItem(refreshedItem);
            } else {
              // Item might have been deleted or changed, soft refresh with loading
              this.detailsService.softRefreshSelectedItem();
            }
          }
        }),
      )
      .subscribe();
  }

  protected handleFilterChange(event: FilterChangeEvent): void {
    this.filterSubject.next({
      field: event.field,
      value: typeof event.value === 'string' ? event.value.trim() : event.value,
    });
  }

  protected handleColumnChange(visibleColumnFields: string[]): void {
    this.visibleColumns.set(visibleColumnFields);

    // Save the preference with validation when columns change
    const config = this.gridConfiguration();
    if (config) {
      this.gridPreferenceService.saveVisibleColumnsWithValidation(
        config,
        visibleColumnFields,
      );
    }
  }

  protected onFilterToggle(): void {
    const config = this.gridConfiguration();
    if (!this.grid || !config) return;

    const newValue = !this.showFilters();
    this.showFilters.set(newValue);

    if (newValue) {
      // When showing filters, sync the current filter state
      if (config.getFilters) {
        const filterState = config.getFilters();
        const currentFilters: Record<string, FilterValue> = {};

        // Convert FilterCriteria objects to FilterValue
        Object.entries(filterState).forEach(([field, criteria]) => {
          if (isDefined(criteria) && typeof criteria === 'object') {
            currentFilters[field] = criteria.value;
          }
        });

        this.currentFilters.set(currentFilters);
      }
    } else if (this.grid.filterable()) {
      if (config.clearFilters) {
        // Call the grid configuration's clearFilters method to restore defaults
        config.clearFilters();

        // Load data with the updated filters that include defaults
        this.loadData().pipe(takeUntilDestroyed(this.destroyRef)).subscribe();
      }
    }
  }

  protected handleLazyLoad(event: TableLazyLoadEvent): void {
    this.loadData(event)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return EMPTY;
        }),
      )
      .subscribe();
  }

  // Handle row selection from the grid
  handleRowSelect(event: TableRowSelectEvent): void {
    if (isEmpty(event) || isEmpty(event.data)) return;

    const routeEntityType = this.detailsFactory.getEntityTypeFromRoute(
      this.activatedRoute,
      'type',
    );
    const entityType = routeEntityType ?? event.data.type;

    const item = { ...event.data, entityType: entityType };

    this.broadcastService.broadcast('grid-item-selected', {
      item,
      componentType: this.detailsFactory.getDetailsComponent(entityType),
    });
  }

  /**
   * Find an item in the current grid data by its ID
   * Used for soft refreshing details panel after grid refresh
   */
  private findItemById(id: string): GridDataType | null {
    const currentData = this.data();
    return currentData?.find((item) => String(item.id) === id) ?? null;
  }
}
